---@class LBattleSkillData
local LBattleSkillData = classX("LBattleSkillData",nil)

function LBattleSkillData:ctor(dataMgr)
    ---@type LBattleDataMgr
    self._dataMgr = dataMgr

    ---@type number 技能类型，用于好感度判断播放的技能音效类型
    self._skinSkillType = nil

    self._expressId = 0

    --- 针对某些技能表现判断
    --- 特殊使用（可不填）
    --- 1=近战（有位移） 例如：小浣熊斩杀移动判断
    self._posOnHook = 0

    --- 技能后续特殊表现 目前用于斩杀追击，索引 技能皮肤表
    self._skillShowEff1List = {}
end

function LBattleSkillData:SetSkinSkillType(skillType)
    self._skinSkillType = skillType
end

function LBattleSkillData:InitData(skillRefId,skillEffId,skillExpressId,bNormal,skinId)
    self._skillRefId = skillRefId

    if skillRefId then
        local skillRef = self:GetSkillRef(skillRefId)
        self._skillRef = skillRef

        self._skillName = I18nText(skillRef.name)

        self._skillNameImage = skillRef.nameIcon
    end


    self._bNormal = bNormal

    self._skillEffId = skillEffId

    self._expressId = skillExpressId --技能表现id
    --local skillExpressId =  expressData.expressionId -- tonumber(skillRef.skillShowEff) or 0


    ---@type V_SkillExpressionRef
    local skillShowEffEf = self:GetSkillExpressionRef(skillExpressId)
    if  not skillShowEffEf then
        if LOG_INFO_ENABLED then
            printError("battle" , string.format("no express cfg refId %s",tostring(skillExpressId)))
        end
        return false
    end

    self._posOnHook = skillShowEffEf.posOnHook

    self._skillShowEff1List = {}

    ---@type V_SkillEffectRef
    local skillEffectRef = self:GetSkillEffectRef(skillEffId)
    if skillEffectRef then
        self._effectType = skillEffectRef.effectType

        if not string.isempty(skillEffectRef.skillShowEff1) then
            local skillShowEff1 = string.split(skillEffectRef.skillShowEff1,"|")
            for i,v in ipairs(skillShowEff1) do
                v = tonumber(v)
                table.insert(self._skillShowEff1List,v)
            end
        end
    end

    local playEff = skillShowEffEf.playEff
    local playEffectMap = {}

    self._playEffectMap = playEffectMap

    --- 判断是否需要检测音效播放
    local needCheckSound = self:IsNeedCheckSound(self._skinSkillType)

    --重新组织 结构，可以方便不需要配置表 就可以自己生成 表演结构
    self._playEffectList = self:ParsePlayEff(playEffectMap,playEff,skinId,needCheckSound)

    local playHitEffTypeInfo = nil
    if not string.isempty(skillShowEffEf.hitEffType) then
        local hitEffType = string.split(skillShowEffEf.hitEffType,"=")

        local hitBulletEffData
        local hitBullet = tonumber(hitEffType[2]) or 0
        if hitBullet and hitBullet > 0 then
            hitBulletEffData = self:_ParamSkillVfxRefData(hitBullet)
        end

        local hitEffRefIdData
        local hitEffRefId = tonumber(hitEffType[3]) or 0
        if hitEffRefId and hitEffRefId > 0 then
            hitEffRefIdData = self:_ParamSkillVfxRefData(hitEffRefId)
        end

        playHitEffTypeInfo = {
            hitEffectType = tonumber(hitEffType[1]) or 0,

            hitBullet = hitBullet,
            hitBulletEffData = hitBulletEffData,

            hitEffRefId = hitEffRefId,
            hitEffRefIdData = hitEffRefIdData,
        }
    end
    self._playHitEffTypeInfo = playHitEffTypeInfo


    --根据延迟时间排序
    --- 按照 delayTime 排序，delayTime 一样则按照 refId 排序
    local sortFunc = self:SortPlayEffectFunc()
    table.sort(self._playEffectList,sortFunc)

    --跟随播放只嵌套一层
    for k,v in ipairs(self._playEffectList) do
        if not string.isempty(v.nextPlay) then
            local playList = self:ParsePlayEff(playEffectMap,v.nextPlay)
            v.nextPlayList = playList
            table.sort(playList,sortFunc)
        end
    end

    --预测大概时间，只计算一层嵌套
    self._skillShowTime,self._skillInclu = self:CalcSkillTime(self._playEffectList,0)

    return true
end

function LBattleSkillData:SortPlayEffectFunc()
    return function (a,b)
        if a.delayTime ~= b.delayTime then
            return a.delayTime < b.delayTime
        end
        return a.refId < b.refId
    end
end

--计算大概时间 --舍弃弹道飞行时间
function LBattleSkillData:CalcSkillTime(playeEffList,depth)
    local maxTime = 0

    local maxIncludeTime = 0
    depth = depth or 0
    for k,v in pairs(playeEffList) do
        local max = v.delayTime + v.playTime
        local maxInclude = v.delayTime + v.playTime
        if v.effType == LSkillEffConst.PLAY_EFF_BULLET then
            maxInclude = maxInclude + self:GetBulletTime()
        end
        if depth == 0 and #v.nextPlayList > 0 then
            local time1,time2 = self:CalcSkillTime(v.nextPlayList,depth + 1)
            max = max + time1
            maxInclude = maxInclude + time2
        end
        if max > maxTime then
            maxTime = max
        end

        if maxInclude> maxIncludeTime then
            maxIncludeTime = maxInclude
        end
    end
    return maxTime,maxIncludeTime
end

function LBattleSkillData:IsNeedCheckSound(skinSkillType)
    return skinSkillType == LFightConst.SKIN_SKILLTYPE_SKILL1 or skinSkillType == LFightConst.SKIN_SKILLTYPE_SKILL2
end

function LBattleSkillData:ParsePlayEff(hadMap,playEffListStr,skinId,needCheckSound)
    local arrPlayEffId = string.split(playEffListStr or "","|") or {}
    local playEffList = {}

    --跟随子弹的动效表现列表
    for k,strId in ipairs(arrPlayEffId) do
        local refId = tonumber(strId)
        local data = self:_ParamSkillVfxRefData(refId,needCheckSound)
        if data then
            hadMap[refId] = data
            table.insert(playEffList,data)
        end
    end
    return playEffList
end

function LBattleSkillData:_ParamSkillVfxRefData(refId,needCheckSound)
    local skillVfxRef = self:GetSkillVfxRef(refId)
    if not skillVfxRef then return end
    return {
        refId = refId,
        effType = skillVfxRef.effType,
        effRes = skillVfxRef.effRes,
        actionReset = skillVfxRef.actionReset,
        delayTime = skillVfxRef.delayTime,
        playTime = skillVfxRef.playTime,
        dissipateTime = skillVfxRef.dissipateTime,
        moveSpeed = skillVfxRef.moveSpeed,
        nextPlay = skillVfxRef.nextPlay,
        excursionIObject = skillVfxRef.excursionIObject,
        effOffsetStart = self:ParseOffset(skillVfxRef.effOffsetStart),
        effOffsetEnd = self:ParseOffset(skillVfxRef.effOffsetEnd),
        effTarget = skillVfxRef.effTarget,
        bulletCdTime = skillVfxRef.bulletCdTime,
        effTargetIndex = skillVfxRef.effTargetIndex,
        bulletTrack = skillVfxRef.bulletTrack,
        playNum = self:ParsePlayNum(skillVfxRef.playNum,skillVfxRef.effType),
        nextPlayList = {},
        soundBattle = skillVfxRef.soundBattle,
        talkTxt = I18nText(skillVfxRef.talkTxt),
        effStartType = skillVfxRef.effOffsetStartType,
        battleHierarchy = skillVfxRef.battleHierarchy or 0,
        boneName = skillVfxRef.boneName,
        needCheckSound = needCheckSound,
        skinSkillType = self._skinSkillType
    }
end

function LBattleSkillData:CopySkillVfxRefData(data)
    return {
        refId = data.refId,
        effType = data.effType,
        effRes = data.effRes,
        actionReset = data.actionReset,
        delayTime = data.delayTime,
        playTime = data.playTime,
        dissipateTime = data.dissipateTime,
        moveSpeed = data.moveSpeed,
        nextPlay = data.nextPlay,
        excursionIObject = data.excursionIObject,
        effOffsetStart = data.effOffsetStart,
        effOffsetEnd = data.effOffsetEnd,
        effTarget = data.effTarget,
        bulletCdTime = data.bulletCdTime,
        effTargetIndex = data.effTargetIndex,
        bulletTrack = data.bulletTrack,
        playNum = data.playNum,
        nextPlayList = data.nextPlayList,
        soundBattle = data.soundBattle,
        talkTxt = data.talkTxt,
        effStartType = data.effOffsetStartType,
        battleHierarchy = data.battleHierarchy,
        boneName = data.boneName,
        needCheckSound = data,
        skinSkillType = data.skinSkillType
    }
end

