---多段受击特效
function LBattleSkillData:RepeatEffectData(playEffList, data)
    local tmpPlayNum = data.playNum
    local cnt = #tmpPlayNum
    if cnt > 0 then
        local delayTime = data.delayTime
        for k,v in ipairs(tmpPlayNum) do
            local copyData = table.light_copy(data)
            copyData.delayTime = delayTime + v
            table.insert(playEffList,copyData)
        end
    end
end

