function LBattleSkillData:ParseOffset(str)
    if string.isempty(str) then return Vector3.zero end
    local offset = LxDataHelper.ParseVector(str)
    return offset
end
--对4类型
--# 用于服务端是同一伤害但使用多次弹道射击
--# 留空=只射1颗
--# 第1与第2间隔cd,第2和第3间隔cd,第3和第4间隔…第n-1和第n颗子弹间隔
function LBattleSkillData:ParsePlayNum(str,effType)
    if string.isempty(str) then return {} end
    local func = self._dataMgr:GetParsePlayNumFunc(effType)
    return func(str)
end


